section.p:
As with the previous options there are different test runners to do this work for you, such as
        JUnit
        for Java,
        Mocha
        for JavaScript,
        XQSuite
        for XQuery. To run your tests, we are going to leverage the support for running unit tests of our build system (e.g.:
        npm test,
        mvm test, etc.):

section.pre:
describe('The dashboard', function() {
  it('should load', function() {
    // Go to Dashboard
    cy.visit('/dashboard/index.html')
  })
  // Click the login button
  describe('login', function() {
    before(function() {
      cy.get('#user_label').click()

      cy.get('#dijit_form_ValidationTextBox_0').type('admin')

      cy.get('#dijit_form_Button_0_label').click()
    })

    // check if Collection browser is there
    it('should see Collection Browser', function() {
      // click Collection Browser
      cy.contains('Collections').click()

      // more tests go here …

      // close the window
      cy.get('#inlineClose')
    })
  })
})
